#!/usr/bin/env node
/**
 * Sync game data from JSON files to Supabase database.
 * 
 * This script reads the game-*.json files generated by parse-extracted-data.mjs
 * and upserts them to the corresponding Supabase tables.
 * 
 * Usage:
 *   node scripts/sync-game-data-to-db.mjs
 * 
 * Requirements:
 *   - SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY in .env
 *   - game-*.json files in src/data/
 */

import { readFileSync, existsSync } from 'fs'
import { join, dirname } from 'path'
import { fileURLToPath } from 'url'
import { createClient } from '@supabase/supabase-js'
import dotenv from 'dotenv'

const __dirname = dirname(fileURLToPath(import.meta.url))
const PROJECT_ROOT = join(__dirname, '..')
const DATA_DIR = join(PROJECT_ROOT, 'src', 'data')

// Load environment variables
dotenv.config({ path: join(PROJECT_ROOT, '.env') })
dotenv.config({ path: join(PROJECT_ROOT, '.env.local') })

const SUPABASE_URL = process.env.SUPABASE_URL || process.env.VITE_SUPABASE_URL
const SUPABASE_SERVICE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY

if (!SUPABASE_URL || !SUPABASE_SERVICE_KEY) {
  console.error('ERROR: Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY')
  console.error('Set these in your .env file')
  process.exit(1)
}

const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_KEY, {
  auth: { persistSession: false }
})

function readJsonFile(filename) {
  const path = join(DATA_DIR, filename)
  if (!existsSync(path)) {
    console.warn(`  Warning: ${filename} not found`)
    return null
  }
  return JSON.parse(readFileSync(path, 'utf-8'))
}

async function syncMining() {
  console.log('\n[1/5] Syncing mining data...')
  
  const data = readJsonFile('game-mining-locations.json')
  if (!data) return { synced: 0, errors: 0 }
  
  const rows = []
  
  // Convert rarity tiers to flat rows
  for (const [rarity, ores] of Object.entries(data.rarityTiers)) {
    for (const ore of ores) {
      rows.push({
        ore_name: ore.name,
        rarity: rarity,
        locations: ore.locations || []
      })
    }
  }
  
  if (rows.length === 0) {
    console.log('  No mining data to sync')
    return { synced: 0, errors: 0 }
  }
  
  // Delete existing and insert new (full refresh)
  const { error: deleteError } = await supabase
    .from('game_mining')
    .delete()
    .neq('id', 0) // Delete all
  
  if (deleteError) {
    console.error('  Error clearing table:', deleteError.message)
    return { synced: 0, errors: 1 }
  }
  
  const { data: inserted, error: insertError } = await supabase
    .from('game_mining')
    .insert(rows)
    .select()
  
  if (insertError) {
    console.error('  Error inserting:', insertError.message)
    return { synced: 0, errors: 1 }
  }
  
  console.log(`  Synced ${rows.length} mining entries`)
  return { synced: rows.length, errors: 0 }
}

async function syncComponents() {
  console.log('\n[2/5] Syncing components data...')
  
  const data = readJsonFile('game-components.json')
  if (!data?.components) return { synced: 0, errors: 0 }
  
  const rows = data.components.map(c => ({
    internal_id: c.name,
    display_name: c.displayName || c.name,
    component_type: c.type,
    type_code: c.type?.substring(0, 4).toUpperCase() || 'UNKN',
    manufacturer: c.manufacturer || 'Unknown',
    manufacturer_code: c.manufacturerCode || 'UNKN',
    size: c.size || 0,
    class: 'Standard', // We don't have class info in new format
    class_code: 'STD',
    grade: String.fromCharCode(65 + (c.grade || 0)), // Convert 0-3 to A-D
    grade_rank: (c.grade || 0) + 1,
    full_label: c.displayName || c.name
  }))
  
  if (rows.length === 0) {
    console.log('  No component data to sync')
    return { synced: 0, errors: 0 }
  }
  
  // Delete existing and insert new
  const { error: deleteError } = await supabase
    .from('game_components')
    .delete()
    .neq('id', 0)
  
  if (deleteError) {
    console.error('  Error clearing table:', deleteError.message)
    return { synced: 0, errors: 1 }
  }
  
  // Insert in batches of 500
  const batchSize = 500
  let synced = 0
  
  for (let i = 0; i < rows.length; i += batchSize) {
    const batch = rows.slice(i, i + batchSize)
    const { error: insertError } = await supabase
      .from('game_components')
      .insert(batch)
    
    if (insertError) {
      console.error(`  Error inserting batch ${i / batchSize + 1}:`, insertError.message)
      return { synced, errors: 1 }
    }
    synced += batch.length
  }
  
  console.log(`  Synced ${synced} components`)
  return { synced, errors: 0 }
}

