async function syncBlueprintPools() {
  console.log('\n[4/5] Syncing blueprint pools...')
  
  const bpData = readJsonFile('game-blueprint-missions.json')
  const repData = readJsonFile('game-reputation.json')
  
  if (!bpData?.missionBlueprints) return { synced: 0, errors: 0 }
  
  // Build a helper to get standing tier from mission
  function getMissionStandingTier(missionKey) {
    if (!repData?.missions) return 'unknown'
    const mission = repData.missions[missionKey]
    if (!mission?.reputationRequirements?.length) return 'neutral'
    
    // Try to resolve the standing reference
    const req = mission.reputationRequirements[0]
    if (!req.standingRef) return 'unknown'
    
    // Extract standing name from file path
    const match = req.standingRef.match(/reputationstanding_(\w+)_(\w+)/i)
    if (match) return match[2].toLowerCase()
    
    return 'unknown'
  }
  
  const rows = Object.entries(bpData.missionBlueprints).map(([missionKey, blueprints]) => ({
    contract_key: missionKey,
    blueprints: blueprints.map(bp => bp.name),
    standing_tier: getMissionStandingTier(missionKey)
  }))
  
  if (rows.length === 0) {
    console.log('  No blueprint pool data to sync')
    return { synced: 0, errors: 0 }
  }
  
  // Delete existing and insert new
  const { error: deleteError } = await supabase
    .from('game_blueprint_pools')
    .delete()
    .neq('id', 0)
  
  if (deleteError) {
    console.error('  Error clearing table:', deleteError.message)
    return { synced: 0, errors: 1 }
  }
  
  // Insert in batches
  const batchSize = 500
  let synced = 0
  
  for (let i = 0; i < rows.length; i += batchSize) {
    const batch = rows.slice(i, i + batchSize)
    const { error: insertError } = await supabase
      .from('game_blueprint_pools')
      .insert(batch)
    
    if (insertError) {
      console.error(`  Error inserting batch:`, insertError.message)
      return { synced, errors: 1 }
    }
    synced += batch.length
  }
  
  console.log(`  Synced ${synced} blueprint pools`)
  return { synced, errors: 0 }
}

async function syncBlueprintStandings() {
  console.log('\n[5/5] Syncing blueprint standings...')
  
  const bpData = readJsonFile('game-blueprint-missions.json')
  const repData = readJsonFile('game-reputation.json')
  
  if (!bpData?.blueprintMissions) return { synced: 0, errors: 0 }
  
  // Helper to get minimum standing for a blueprint across its missions
  function getMinStanding(missionKeys) {
    if (!repData?.missions) return 'unknown'
    
    let minRep = Infinity
    let minStandingName = 'neutral'
    
    for (const missionKey of missionKeys) {
      const mission = repData.missions[missionKey]
      if (!mission) continue
      
      if (!mission.reputationRequirements?.length) {
        // No rep requirement = neutral (0)
        if (0 < minRep) {
          minRep = 0
          minStandingName = 'neutral'
        }
        continue
      }
      
      // Try to get rep value from standing reference
      const req = mission.reputationRequirements[0]
      const match = req.standingRef?.match(/reputationstanding_(\w+)_(\w+)/i)
      if (match) {
        const standingName = match[2].toLowerCase()
        // Look up in standings data
        const category = match[1].toLowerCase()
        const standings = repData.standingsByCategory?.[category]
        if (standings) {
          const standing = standings.find(s => 
            s.filePath?.toLowerCase().includes(standingName)
          )
          if (standing && standing.minReputation < minRep) {
            minRep = standing.minReputation
            minStandingName = standing.displayName || standingName
          }
        }
      }
    }
    
    return minRep === Infinity ? 'unknown' : minStandingName
  }
  
  const rows = Object.entries(bpData.blueprintMissions).map(([blueprintName, missions]) => ({
    blueprint_name: blueprintName,
    min_standing: getMinStanding(missions),
    contract_keys: missions
  }))
  
  if (rows.length === 0) {
    console.log('  No blueprint standing data to sync')
    return { synced: 0, errors: 0 }
  }
  
  // Delete existing and insert new
  const { error: deleteError } = await supabase
    .from('game_blueprint_standings')
    .delete()
    .neq('id', 0)
  
  if (deleteError) {
    console.error('  Error clearing table:', deleteError.message)
    return { synced: 0, errors: 1 }
  }
  
  // Insert in batches
  const batchSize = 500
  let synced = 0
  
  for (let i = 0; i < rows.length; i += batchSize) {
    const batch = rows.slice(i, i + batchSize)
    const { error: insertError } = await supabase
      .from('game_blueprint_standings')
      .insert(batch)
    
    if (insertError) {
      console.error(`  Error inserting batch:`, insertError.message)
      return { synced, errors: 1 }
    }
    synced += batch.length
  }
  
  console.log(`  Synced ${synced} blueprint standings`)
  return { synced, errors: 0 }
}

async function updateSyncMeta(results) {
  const { error } = await supabase
    .from('game_sync_meta')
    .upsert({
      id: 1,
      last_synced_at: new Date().toISOString(),
      source_version: 'local-extraction',
      sync_status: results.totalErrors > 0 ? 'error' : 'success',
      sync_error: results.totalErrors > 0 ? `${results.totalErrors} errors occurred` : null,
      updated_at: new Date().toISOString()
    })
  
  if (error) {
    console.warn('  Warning: Could not update sync meta:', error.message)
  }
}

async function main() {
  console.log('='.repeat(60))
  console.log('  Game Data -> Supabase Sync')
  console.log('='.repeat(60))
  console.log(`\nUsing: ${SUPABASE_URL}`)
  
  const results = {
    mining: await syncMining(),
    components: await syncComponents(),
    ordnance: await syncOrdnance(),
    blueprintPools: await syncBlueprintPools(),
    blueprintStandings: await syncBlueprintStandings(),
    totalErrors: 0
  }
  
  results.totalErrors = Object.values(results)
    .filter(r => typeof r === 'object' && r.errors)
    .reduce((sum, r) => sum + r.errors, 0)
  
  await updateSyncMeta(results)
  
  console.log('\n' + '='.repeat(60))
  console.log('  Sync Summary')
  console.log('='.repeat(60))
  console.log(`  Mining:            ${results.mining.synced} rows`)
  console.log(`  Components:        ${results.components.synced} rows`)
  console.log(`  Ordnance:          ${results.ordnance.synced} rows`)
  console.log(`  Blueprint Pools:   ${results.blueprintPools.synced} rows`)
  console.log(`  Blueprint Standings: ${results.blueprintStandings.synced} rows`)
  
  if (results.totalErrors > 0) {
    console.log(`\n⚠️  ${results.totalErrors} error(s) occurred during sync`)
    process.exit(1)
  } else {
    console.log('\n✓ Sync completed successfully')
  }
}

main().catch(err => {
  console.error('Fatal error:', err)
  process.exit(1)
})
